
CREATE DATABASE IF NOT EXISTS recantoceuazul;
USE recantoceuazul;

CREATE TABLE IF NOT EXISTS ator (
    id INTEGER PRIMARY KEY AUTO_INCREMENT,
    email VARCHAR(100),
    telefone VARCHAR(15),
    nome VARCHAR(100),
    senha VARCHAR(255),
    papel VARCHAR (5)
);

CREATE TABLE IF NOT EXISTS medicao (
    id INTEGER PRIMARY KEY AUTO_INCREMENT,
    volume_agua FLOAT,
    delta FLOAT,
    data_medicao DATETIME,
    fk_Residencia_id INTEGER,
    fk_Ator_id INTEGER
);

CREATE TABLE IF NOT EXISTS residencia (
    id INTEGER PRIMARY KEY AUTO_INCREMENT,
    numero INTEGER
);

CREATE TABLE IF NOT EXISTS possuir (
    fk_Ator_id INTEGER,
    fk_Residencia_id INTEGER
);
 
ALTER TABLE medicao ADD CONSTRAINT FK_Medicao_2
    FOREIGN KEY (fk_Residencia_id)
    REFERENCES residencia (id)
    ON DELETE CASCADE;
 
ALTER TABLE medicao ADD CONSTRAINT FK_Medicao_3
    FOREIGN KEY (fk_Ator_id)
    REFERENCES ator (id)
    ON DELETE SET NULL;
 
ALTER TABLE possuir ADD CONSTRAINT FK_Possuir_1
    FOREIGN KEY (fk_Ator_id)
    REFERENCES ator (id)
    ON DELETE RESTRICT;
 
ALTER TABLE possuir ADD CONSTRAINT FK_Possuir_2
    FOREIGN KEY (fk_Residencia_id)
    REFERENCES residencia (id)
    ON DELETE SET NULL;

CREATE OR REPLACE VIEW v_media_consumo_condominio AS
SELECT
    DATE_FORMAT(data_medicao, '%m/%Y') AS MesAno,
    ROUND(AVG(delta), 2) AS MediaConsumo
FROM
    medicao
GROUP BY
    DATE_FORMAT(data_medicao, '%m/%Y')
ORDER BY
	DATE_FORMAT(data_medicao, '%m/%Y');

CREATE OR REPLACE VIEW v_dashboard_mensal AS
SELECT
    DATE_FORMAT(m.data_medicao, '%m/%Y') AS MesAno,
    
    -- Consumo Total: A SOMA de todo o consumo (delta) no mês
    ROUND(SUM(m.delta), 2) AS ConsumoTotal,
    
    -- Medições Realizadas: CONCAT do total de medições no mês / total de residências
    CONCAT(
        COUNT(m.id), 
        '/', 
        r_total.total_residencias
    ) AS MedicoesRealizadas,
    
    -- Média de Consumo: A MÉDIA do 'delta' das medições daquele mês
    ROUND(AVG(m.delta), 2) AS MediaConsumo
FROM
    medicao m
CROSS JOIN 
    -- Usamos CROSS JOIN para trazer o número total de residências
    (SELECT COUNT(*) AS total_residencias FROM residencia) AS r_total
GROUP BY
    DATE_FORMAT(m.data_medicao, '%m/%Y'), 
    r_total.total_residencias
ORDER BY
	DATE_FORMAT(m.data_medicao, '%m/%Y') DESC;
SELECT * FROM v_dashboard_mensal;

